#include <stdio.h>
#include <stdlib.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int X, Y; scanf("%d %d", &X, &Y);
        int ans = abs(X - Y);
        printf("%d\n", ans);
    }
    return 0;
}

